from functools import wraps
import time as pytime


def retry(max_attempts: int = 3, delay_seconds: float = 1.0):
    """
    Retry decorator that retries a function up to max_attempts times if it raises an exception.

    Args:
        max_attempts (int): Maximum number of attempts including the first try. Default is 3.
        delay_seconds (float): Seconds to wait between retry attempts. Default is 1 second.

    Raises:
        Exception: Re-raises whatever exception was raised if all retries exhausted, after optional error handling configuration.

    Returns:
        The result of the function call on success; original exceptions are re-raised on failure unless overridden via `on_error` callback or default behavior.
    """

    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            attempt = 0
            last_exception = None

            while True:
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    last_exception = e
                    if attempt >= max_attempts - 1:
                        break

                    print(f"Attempt {attempt + 2}/{max_attempts} failed. Retrying in {delay_seconds}s...")
                    time.sleep(delay_seconds)
                    attempt += 1

            raise last_exception

        return wrapper

    # Optional error handling via `on_error` callback (can be overridden at usage site):

    def on_error(exc, fn_name=""):
        """Optional function to handle retry errors. Used by caller instead of raising."""
        print(f"Error after {max_attempts} attempts for func: '{fn_name}'")

    decorator_on_error = None

